import{_ as e,o as t,c as a,ag as o}from"./chunks/framework.CHQlKclR.js";const k=JSON.parse('{"title":"Motion Control","description":"","frontmatter":{},"headers":[],"relativePath":"api/motion-control.md","filePath":"api/motion-control.md"}'),s={name:"api/motion-control.md"};function n(l,i,r,d,h,c){return t(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="motion-control" tabindex="-1">Motion Control <a class="header-anchor" href="#motion-control" aria-label="Permalink to &quot;Motion Control&quot;">​</a></h1><p>The <code>vortex::Drive</code> class provides a high-level API for precise, closed-loop PID movements. These functions handle everything from simple straight drives to complex coordinate-based turns.</p><h2 id="movement-primitives" tabindex="-1">Movement Primitives <a class="header-anchor" href="#movement-primitives" aria-label="Permalink to &quot;Movement Primitives&quot;">​</a></h2><p>Every movement function in Vortex follows a consistent naming convention: <code>pid_[type]_set</code>.</p><h3 id="driving" tabindex="-1">Driving <a class="header-anchor" href="#driving" aria-label="Permalink to &quot;Driving&quot;">​</a></h3><h4 id="pid-drive-set" tabindex="-1"><code>pid_drive_set</code> <a class="header-anchor" href="#pid-drive-set" aria-label="Permalink to &quot;`pid_drive_set`&quot;">​</a></h4><p>Moves the robot forward or backward a specified distance.</p><ul><li><code>okapi::QLength target</code> / <code>double inches</code>: The distance to travel.</li><li><code>int speed</code>: Max power (0-127).</li><li><code>bool slew_on</code> (optional): Enables/disables acceleration ramping for this motion.</li></ul><h3 id="turning" tabindex="-1">Turning <a class="header-anchor" href="#turning" aria-label="Permalink to &quot;Turning&quot;">​</a></h3><h4 id="pid-turn-set" tabindex="-1"><code>pid_turn_set</code> <a class="header-anchor" href="#pid-turn-set" aria-label="Permalink to &quot;`pid_turn_set`&quot;">​</a></h4><p>Rotates the robot to a global or relative heading.</p><ul><li><code>okapi::QAngle target</code> / <code>double degrees</code>: The target angle.</li><li><code>int speed</code>: Max power (0-127).</li><li><code>e_angle_behavior behavior</code> (optional): <code>shortest</code>, <code>left_turn</code>, etc.</li></ul><h4 id="pid-turn-relative-set" tabindex="-1"><code>pid_turn_relative_set</code> <a class="header-anchor" href="#pid-turn-relative-set" aria-label="Permalink to &quot;`pid_turn_relative_set`&quot;">​</a></h4><p>Rotates the robot relative to its <strong>current</strong> heading.</p><h3 id="swings" tabindex="-1">Swings <a class="header-anchor" href="#swings" aria-label="Permalink to &quot;Swings&quot;">​</a></h3><h4 id="pid-swing-set" tabindex="-1"><code>pid_swing_set</code> <a class="header-anchor" href="#pid-swing-set" aria-label="Permalink to &quot;`pid_swing_set`&quot;">​</a></h4><p>Pivots the robot using only one side of the drivetrain.</p><ul><li><code>e_swing type</code>: <code>LEFT_SWING</code> or <code>RIGHT_SWING</code>.</li><li><code>double target</code>: Target angle in degrees.</li><li><code>int speed</code>: Max power (0-127).</li><li><code>int opposite_speed</code> (optional): Allows for &quot;arcing&quot; by giving the non-pivoting side some power.</li></ul><hr><h2 id="timed-blocking-motions" tabindex="-1">Timed (Blocking) Motions <a class="header-anchor" href="#timed-blocking-motions" aria-label="Permalink to &quot;Timed (Blocking) Motions&quot;">​</a></h2><p>By default, the <code>set</code> functions above are <strong>non-blocking</strong> (they return immediately while the robot moves in the background).</p><p>Vortex provides <strong>Timed Overloads</strong> for every motion. Simply add an <code>okapi::QTime</code> (e.g., <code>2000_ms</code>) as the final argument to make the function block until the robot settles or the timeout expires.</p><h3 id="example-blocking-vs-non-blocking" tabindex="-1">Example: Blocking vs Non-Blocking <a class="header-anchor" href="#example-blocking-vs-non-blocking" aria-label="Permalink to &quot;Example: Blocking vs Non-Blocking&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Non-blocking: starts moving and immediately runs and next line</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chassis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pid_drive_set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">_in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">110</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">do_something_else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); </span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Blocking: waits up to 2 seconds for the robot to finish</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chassis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pid_drive_set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">_in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">110</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">_ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">next_auton_step</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><hr><h2 id="synchronization-waiting" tabindex="-1">Synchronization &amp; Waiting <a class="header-anchor" href="#synchronization-waiting" aria-label="Permalink to &quot;Synchronization &amp; Waiting&quot;">​</a></h2><p>If you use non-blocking motions, you can use these methods to synchronize your code.</p><h3 id="pid-wait-int-timeout-ms-0" tabindex="-1"><code>pid_wait(int timeout_ms = 0)</code> <a class="header-anchor" href="#pid-wait-int-timeout-ms-0" aria-label="Permalink to &quot;`pid_wait(int timeout_ms = 0)`&quot;">​</a></h3><p>Blocks the current task until the robot has settled at its target. If a global timeout is set, it will be used if <code>0</code> is passed.</p><h3 id="pid-wait-until-double-target" tabindex="-1"><code>pid_wait_until(double target)</code> <a class="header-anchor" href="#pid-wait-until-double-target" aria-label="Permalink to &quot;`pid_wait_until(double target)`&quot;">​</a></h3><p>Blocks until the robot has passed a certain distance or angle.</p><ul><li>For driving: Blocks until robot passes <code>target</code> inches.</li><li>For turning: Blocks until robot passes <code>target</code> degrees.</li></ul><h3 id="pid-wait-quick" tabindex="-1"><code>pid_wait_quick()</code> <a class="header-anchor" href="#pid-wait-quick" aria-label="Permalink to &quot;`pid_wait_quick()`&quot;">​</a></h3><p>A faster version of <code>pid_wait</code> that exits as soon as the robot enters the &quot;small error&quot; range, without waiting for it to fully settle/stop oscillating.</p><h3 id="pid-wait-quick-chain" tabindex="-1"><code>pid_wait_quick_chain()</code> <a class="header-anchor" href="#pid-wait-quick-chain" aria-label="Permalink to &quot;`pid_wait_quick_chain()`&quot;">​</a></h3><p>Similar to <code>pid_wait_quick</code>, but optimized for &quot;chaining&quot; motions together (e.g., driving then immediately turning without losing momentum).</p>',36)])])}const u=e(s,[["render",n]]);export{k as __pageData,u as default};
